{
  "name": "ARP Care Platform Demo",
  "description": "A multi-agent elderly monitoring system simulating an end-to-end care workflow from check-in to follow-up coaching.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AgentID {
  CHECK_IN = 'CHECK_IN',
  NORMALIZATION = 'NORMALIZATION',
  RISK_TRIAGE = 'RISK_TRIAGE',
  ORCHESTRATOR = 'ORCHESTRATOR',
  COACH = 'COACH'
}

export enum RiskLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  URGENT = 'URGENT'
}

export interface Patient {
  id: string;
  name: string;
  age: number;
  condition: string;
  status: 'active' | 'stable' | 'monitoring';
}

export interface AgentResponse {
  agentId: AgentID;
  title: string;
  timestamp: string;
  data: any;
  rawJson: string;
  status: 'pending' | 'completed' | 'error';
}

export interface WorkflowState {
  currentStep: number;
  responses: Record<string, AgentResponse>;
  isLoading: boolean;
  error?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AgentID, RiskLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_PROMPTS = {
  [AgentID.CHECK_IN]: `You are the "Care Check-in Agent". Your role is to transcribe and summarize a simulated voice call from an elderly patient. 
Focus on capturing their symptoms, mood, and daily activities. Do not diagnose. Output JSON.`,

  [AgentID.NORMALIZATION]: `You are the "Data Capture & Normalization Agent". 
From a summary of a patient check-in, extract structured vitals, medication adherence, and primary complaints into a clean JSON object. 
If values are missing, mark them null.`,

  [AgentID.RISK_TRIAGE]: `You are the "Risk & Triage Agent". 
Analyze structured patient data. Categorize risk as LOW, MEDIUM, HIGH, or URGENT. 
If URGENT (red flags like chest pain), trigger immediate emergency protocols. 
Provide a clear rationale but DO NOT provide a medical diagnosis. Output JSON.`,

  [AgentID.ORCHESTRATOR]: `You are the "Care Orchestrator Agent". 
Based on a risk assessment, assign tasks to a human Clinical Nurse, a Family Member, and the Primary Care Physician. 
Prioritize tasks based on urgency. Output JSON.`,

  [AgentID.COACH]: `You are the "Care Coach Agent". 
Generate personalized, empathetic guidance for the patient and their family. 
Include educational points about their symptoms and suggestions for improved self-care. Output JSON.`
};

export async function callAgent(agentId: AgentID, context: any) {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Context: ${JSON.stringify(context)}

    Task: Execute your agent role based on the context above.
    Format your output strictly as a JSON object.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_PROMPTS[agentId],
      responseMimeType: "application/json",
    },
  });

  return JSON.parse(response.text);
}

import React, { useState, useCallback } from 'react';
import { callAgent } from './services/gemini';
import { AgentID, WorkflowState, Patient, AgentResponse } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import WorkflowVisualizer from './components/WorkflowVisualizer';
import AgentTerminal from './components/AgentTerminal';
import Header from './components/Header';

const DEMO_PATIENTS: Patient[] = [
  { id: '1', name: 'Mrs. Evelyn Miller', age: 82, condition: 'Congestive Heart Failure', status: 'monitoring' },
  { id: '2', name: 'Mr. Arthur Chen', age: 79, condition: 'Type 2 Diabetes', status: 'stable' },
  { id: '3', name: 'Mrs. Dolores Vance', age: 85, condition: 'Post-Hip Surgery Recovery', status: 'active' },
];

const App: React.FC = () => {
  const [selectedPatient, setSelectedPatient] = useState<Patient>(DEMO_PATIENTS[0]);
  const [workflow, setWorkflow] = useState<WorkflowState>({
    currentStep: 0,
    responses: {},
    isLoading: false,
  });

  const resetWorkflow = () => {
    setWorkflow({
      currentStep: 0,
      responses: {},
      isLoading: false,
    });
  };

  const handleRunWorkflow = async (scenarioText: string) => {
    setWorkflow(prev => ({ ...prev, isLoading: true, currentStep: 1, responses: {} }));

    try {
      // Step 1: Check-in
      const checkInData = await callAgent(AgentID.CHECK_IN, { patient: selectedPatient, callTranscript: scenarioText });
      const checkInResponse: AgentResponse = {
        agentId: AgentID.CHECK_IN,
        title: 'Voice Check-in Analysis',
        timestamp: new Date().toLocaleTimeString(),
        data: checkInData,
        rawJson: JSON.stringify(checkInData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 2, responses: { ...prev.responses, [AgentID.CHECK_IN]: checkInResponse } }));

      // Step 2: Normalization
      const normData = await callAgent(AgentID.NORMALIZATION, { checkInSummary: checkInData });
      const normResponse: AgentResponse = {
        agentId: AgentID.NORMALIZATION,
        title: 'Data Normalization',
        timestamp: new Date().toLocaleTimeString(),
        data: normData,
        rawJson: JSON.stringify(normData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 3, responses: { ...prev.responses, [AgentID.NORMALIZATION]: normResponse } }));

      // Step 3: Risk & Triage
      const riskData = await callAgent(AgentID.RISK_TRIAGE, { structuredData: normData });
      const riskResponse: AgentResponse = {
        agentId: AgentID.RISK_TRIAGE,
        title: 'Risk Assessment & Triage',
        timestamp: new Date().toLocaleTimeString(),
        data: riskData,
        rawJson: JSON.stringify(riskData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 4, responses: { ...prev.responses, [AgentID.RISK_TRIAGE]: riskResponse } }));

      // Step 4: Orchestrator
      const orchData = await callAgent(AgentID.ORCHESTRATOR, { triageResult: riskData, patient: selectedPatient });
      const orchResponse: AgentResponse = {
        agentId: AgentID.ORCHESTRATOR,
        title: 'Care Orchestration',
        timestamp: new Date().toLocaleTimeString(),
        data: orchData,
        rawJson: JSON.stringify(orchData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 5, responses: { ...prev.responses, [AgentID.ORCHESTRATOR]: orchResponse } }));

      // Step 5: Coach
      const coachData = await callAgent(AgentID.COACH, { fullContext: { checkInData, normData, riskData, orchData } });
      const coachResponse: AgentResponse = {
        agentId: AgentID.COACH,
        title: 'Care Coaching & Guidance',
        timestamp: new Date().toLocaleTimeString(),
        data: coachData,
        rawJson: JSON.stringify(coachData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ 
        ...prev, 
        currentStep: 6, 
        isLoading: false, 
        responses: { ...prev.responses, [AgentID.COACH]: coachResponse } 
      }));

    } catch (err: any) {
      console.error(err);
      setWorkflow(prev => ({ ...prev, isLoading: false, error: 'Agent orchestration failed. Please check connectivity.' }));
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        patients={DEMO_PATIENTS} 
        selectedId={selectedPatient.id} 
        onSelect={setSelectedPatient} 
      />

      <div className="flex-1 flex flex-col h-full">
        <Header />

        <main className="flex-1 overflow-y-auto p-6 space-y-6">
          <Dashboard 
            patient={selectedPatient} 
            onTriggerScenario={handleRunWorkflow} 
            isProcessing={workflow.isLoading}
            onReset={resetWorkflow}
          />

          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
            <div className="xl:col-span-2">
              <WorkflowVisualizer 
                currentStep={workflow.currentStep} 
                responses={workflow.responses}
                isLoading={workflow.isLoading}
              />
            </div>
            <div className="xl:col-span-1">
              <AgentTerminal 
                responses={workflow.responses} 
                activeStep={workflow.currentStep} 
              />
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

