export default Sidebar;

import React, { useState } from 'react';
import { Patient } from '../types';

interface DashboardProps {
  patient: Patient;
  onTriggerScenario: (text: string) => void;
  isProcessing: boolean;
  onReset: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ patient, onTriggerScenario, isProcessing, onReset }) => {
  const [scenarioInput, setScenarioInput] = useState('');

  const PRESETS = [
    { label: 'Morning Dizziness', text: "Mrs. Miller called at 8:15 AM. She sounds slightly confused. She said 'I feel a bit woozy this morning, like the room is spinning when I stand up. I think I forgot my white pill.' She denied chest pain but mentioned her legs feel heavier than usual." },
    { label: 'Routine Check-in', text: "Incoming automated call response: 'Everything is fine today. I slept well. I took all my medications with breakfast. No swelling in my ankles today. I'm going to the community garden later.'" },
    { label: 'Red Flag Alert', text: "Voice Alert: 'I'm having trouble catching my breath even while sitting. My chest feels very tight, like someone is squeezing it. I can't find my inhaler. Please help.'" }
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Patient Overview</h2>
          <p className="text-slate-500">Managing care for {patient.name} ({patient.age}y/o)</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={onReset}
            className="px-4 py-2 text-slate-600 font-semibold text-sm bg-white border border-slate-200 rounded-lg hover:bg-slate-50"
          >
            Clear Workflow
          </button>
          <button className="px-4 py-2 bg-indigo-600 text-white font-semibold text-sm rounded-lg shadow-lg shadow-indigo-200 hover:bg-indigo-700">
            Export Report
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Blood Pressure', value: '138/84', icon: 'fa-heart-pulse', color: 'text-rose-500', trend: 'up' },
          { label: 'Oxygen Sat.', value: '96%', icon: 'fa-lungs', color: 'text-blue-500', trend: 'stable' },
          { label: 'Heart Rate', value: '72 bpm', icon: 'fa-wave-square', color: 'text-amber-500', trend: 'down' },
          { label: 'Med Adherence', value: '92%', icon: 'fa-pills', color: 'text-emerald-500', trend: 'up' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-tight">{stat.label}</span>
              <i className={`fa-solid ${stat.icon} ${stat.color}`}></i>
            </div>
            <div className="flex items-end gap-2">
              <span className="text-xl font-bold text-slate-900">{stat.value}</span>
              <span className={`text-[10px] font-bold pb-1 ${
                stat.trend === 'up' ? 'text-rose-500' : stat.trend === 'down' ? 'text-indigo-500' : 'text-slate-400'
              }`}>
                {stat.trend === 'up' ? '▲ 2%' : stat.trend === 'down' ? '▼ 1%' : '• Stable'}
              </span>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-indigo-900 rounded-2xl p-6 text-white shadow-xl">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-indigo-500/30 rounded-full flex items-center justify-center">
            <i className="fa-solid fa-microphone-lines text-indigo-200"></i>
          </div>
          <div>
            <h3 className="font-bold text-lg">Simulate Voice Interaction</h3>
            <p className="text-indigo-300 text-sm">Input raw voice transcript or select a demo scenario to trigger the agents.</p>
          </div>
        </div>

        <div className="space-y-4">
          <textarea
            value={scenarioInput}
            onChange={(e) => setScenarioInput(e.target.value)}
            placeholder="Paste a call transcript here..."
            className="w-full h-24 bg-indigo-950/50 border border-indigo-700/50 rounded-xl p-4 text-indigo-100 placeholder:text-indigo-400 focus:outline-none focus:border-indigo-400 transition-colors resize-none"
          ></textarea>

          <div className="flex flex-wrap gap-2">
            {PRESETS.map((p, idx) => (
              <button
                key={idx}
                onClick={() => setScenarioInput(p.text)}
                className="px-3 py-1.5 bg-indigo-800 hover:bg-indigo-700 text-xs font-semibold rounded-full transition-colors border border-indigo-700"
              >
                {p.label}
              </button>
            ))}
          </div>

          <button
            disabled={isProcessing || !scenarioInput.trim()}
            onClick={() => onTriggerScenario(scenarioInput)}
            className={`w-full py-4 rounded-xl font-bold text-sm tracking-widest flex items-center justify-center gap-2 transition-all ${
              isProcessing 
              ? 'bg-slate-700 cursor-not-allowed text-slate-400' 
              : 'bg-white text-indigo-900 hover:bg-indigo-50 active:scale-[0.98]'
            }`}
          >
            {isProcessing ? (
              <>
                <i className="fa-solid fa-spinner animate-spin"></i>
                ORCHESTRATING AGENTS...
              </>
            ) : (
              <>
                <i className="fa-solid fa-play"></i>
                PROCESS CARE EVENT
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { AgentID, AgentResponse } from '../types';

interface WorkflowVisualizerProps {
  currentStep: number;
  responses: Record<string, AgentResponse>;
  isLoading: boolean;
}

const AGENT_META = [
  { id: AgentID.CHECK_IN, label: 'Check-in', icon: 'fa-phone-volume', color: 'indigo' },
  { id: AgentID.NORMALIZATION, label: 'Normalize', icon: 'fa-filter', color: 'blue' },
  { id: AgentID.RISK_TRIAGE, label: 'Risk & Triage', icon: 'fa-shield-heart', color: 'rose' },
  { id: AgentID.ORCHESTRATOR, label: 'Orchestrator', icon: 'fa-diagram-project', color: 'amber' },
  { id: AgentID.COACH, label: 'Care Coach', icon: 'fa-graduation-cap', color: 'emerald' },
];

const WorkflowVisualizer: React.FC<WorkflowVisualizerProps> = ({ currentStep, responses, isLoading }) => {
  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden h-full">
      <div className="px-6 py-4 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
          <i className="fa-solid fa-network-wired text-indigo-600"></i>
          Active Care Chain
        </h3>
        {isLoading && (
          <div className="flex items-center gap-2 text-indigo-600 text-xs font-bold uppercase tracking-widest">
            <i className="fa-solid fa-circle-notch animate-spin"></i>
            Agents working...
          </div>
        )}
      </div>

      <div className="p-8">
        <div className="relative">
          {/* Timeline Line */}
          <div className="absolute top-[40px] left-[5%] right-[5%] h-1 bg-slate-100 z-0"></div>
          <div 
            className="absolute top-[40px] left-[5%] h-1 bg-indigo-600 z-0 transition-all duration-700 ease-out"
            style={{ width: `${Math.max(0, (currentStep - 1) * 22.5)}%` }}
          ></div>

          <div className="flex justify-between items-start relative z-10">
            {AGENT_META.map((agent, idx) => {
              const status = responses[agent.id] ? 'completed' : currentStep === idx + 1 ? 'active' : 'pending';
              const isLast = idx === AGENT_META.length - 1;

              return (
                <div key={agent.id} className="flex flex-col items-center text-center max-w-[120px]">
                  <div className={`w-20 h-20 rounded-2xl flex items-center justify-center transition-all duration-500 shadow-lg ${
                    status === 'completed' ? `bg-${agent.color}-600 text-white scale-100` : 
                    status === 'active' ? `bg-white border-4 border-indigo-600 text-indigo-600 scale-110 animate-pulse` : 
                    'bg-slate-100 text-slate-400'
                  }`}>
                    <i className={`fa-solid ${agent.icon} text-2xl`}></i>
                  </div>
                  <div className="mt-4">
                    <p className={`text-sm font-bold ${status === 'pending' ? 'text-slate-400' : 'text-slate-900'}`}>
                      {agent.label}
                    </p>
                    <p className="text-[10px] font-semibold text-slate-400 uppercase mt-1">
                      {status === 'completed' ? 'Response Ready' : status === 'active' ? 'Analyzing...' : 'Waiting'}
                    </p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="mt-12 space-y-4">
          {Object.values(responses).map((resp) => (
            <div key={resp.agentId} className="bg-slate-50 border border-slate-200 rounded-xl p-5 hover:border-indigo-300 transition-colors animate-in fade-in slide-in-from-bottom-2">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-3">
                  <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${
                    resp.agentId === AgentID.RISK_TRIAGE ? 'bg-rose-100 text-rose-700' : 'bg-indigo-100 text-indigo-700'
                  }`}>
                    {resp.agentId.replace('_', ' ')}
                  </span>
                  <h4 className="font-bold text-slate-900">{resp.title}</h4>
                </div>
                <span className="text-xs text-slate-400 font-mono">{resp.timestamp}</span>
              </div>

              <div className="text-sm text-slate-600 leading-relaxed">
                {renderAgentContent(resp)}
              </div>
            </div>
          ))}

          {currentStep === 0 && !isLoading && (
            <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl text-slate-400">
              <i className="fa-solid fa-robot text-4xl mb-4 opacity-20"></i>
              <p className="font-medium">Trigger a scenario to begin the care orchestration</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const renderAgentContent = (resp: AgentResponse) => {
  const data = resp.data;
  switch (resp.agentId) {
    case AgentID.CHECK_IN:
      return (
        <div className="grid grid-cols-2 gap-4">
          <div><span className="font-bold text-slate-900 block mb-1">Key Summary</span>{data.summary || data.key_points}</div>
          <div><span className="font-bold text-slate-900 block mb-1">Sentiment/Mood</span>{data.mood || data.sentiment}</div>
        </div>
      );
    case AgentID.NORMALIZATION:
      return (
        <div className="flex flex-wrap gap-2">
          {Object.entries(data).map(([k, v]) => (
            <div key={k} className="bg-white border border-slate-200 px-3 py-1.5 rounded-lg">
              <span className="text-[10px] text-slate-400 uppercase font-bold block">{k.replace('_', ' ')}</span>
              <span className="text-sm font-semibold">{String(v)}</span>
            </div>
          ))}
        </div>
      );
    case AgentID.RISK_TRIAGE:
      return (
        <div className="flex gap-4 items-start">
          <div className={`px-4 py-2 rounded-xl text-white font-black text-center shrink-0 ${
            data.risk_level === 'URGENT' ? 'bg-red-600' : data.risk_level === 'HIGH' ? 'bg-orange-500' : 'bg-emerald-500'
          }`}>
            {data.risk_level}
          </div>
          <p>{data.reasoning || data.rationale}</p>
        </div>
      );
    case AgentID.ORCHESTRATOR:
      return (
        <div className="space-y-3">
          {Array.isArray(data.tasks) ? data.tasks.map((t: any, idx: number) => (
             <div key={idx} className="flex items-center gap-3 bg-white p-2 rounded-lg border border-slate-100">
                <i className="fa-solid fa-circle-check text-indigo-500"></i>
                <div>
                  <span className="text-[10px] font-bold text-slate-400">{t.assignee}</span>
                  <p className="text-xs font-medium text-slate-800">{t.action || t.description}</p>
                </div>
             </div>
          )) : <p>Tasks assigned to medical staff and family contacts.</p>}
        </div>
      );
    case AgentID.COACH:
      return (
        <div className="italic text-slate-700 bg-emerald-50 p-4 rounded-xl border border-emerald-100">
          "{data.guidance || data.message || data.patient_advice}"
        </div>
      );
    default:
      return <pre className="text-[10px] font-mono whitespace-pre-wrap">{JSON.stringify(data, null, 2)}</pre>;
  }
};

export default WorkflowVisualizer;

import React, { useState } from 'react';
import { AgentID, AgentResponse } from '../types';

interface AgentTerminalProps {
  responses: Record<string, AgentResponse>;
  activeStep: number;
}

const AgentTerminal: React.FC<AgentTerminalProps> = ({ responses, activeStep }) => {
