const renderAgentContent = (resp: AgentResponse) => {
  const data = resp.data;
  switch (resp.agentId) {
    case AgentID.CHECK_IN:
      return (
        <div className="space-y-2">
          <div className="p-3 bg-white rounded border border-slate-200">
            <span className="font-bold text-slate-900 block text-[10px] uppercase mb-1">Check-in Analysis</span>
            {data.summary}
          </div>
          <div className="flex gap-4">
            <div><span className="font-bold text-[10px] text-slate-400 uppercase">Contact Status:</span> <span className="font-semibold text-slate-900">{data.contact_status}</span></div>
            <div><span className="font-bold text-[10px] text-slate-400 uppercase">Initial Priority:</span> <span className="font-semibold text-slate-900">{data.initial_priority}</span></div>
          </div>
        </div>
      );
    case AgentID.NORMALIZATION:
      return (
        <div className="space-y-3">
           <div className="flex flex-wrap gap-2">
            {data.vitals && Object.entries(data.vitals).map(([k, v]) => (
              <div key={k} className="bg-white border border-slate-200 px-3 py-1 rounded-lg">
                <span className="text-[10px] text-slate-400 uppercase font-bold block">{k}</span>
                <span className="text-sm font-semibold">{String(v)}</span>
              </div>
            ))}
          </div>
          <div className="text-xs italic bg-blue-50/50 p-2 border-l-2 border-blue-400">
            Entry: {data.timeline_entry}
          </div>
          {data.data_quality_flags?.length > 0 && (
            <div className="flex gap-2 items-center">
              <i className="fa-solid fa-triangle-exclamation text-amber-500 text-xs"></i>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Flags: {data.data_quality_flags.join(', ')}</span>
            </div>
          )}
        </div>
      );
    case AgentID.RISK_TRIAGE:
      return (
        <div className="flex gap-4 items-start">
          <div className={`px-4 py-2 rounded-xl text-white font-black text-center shrink-0 flex flex-col items-center justify-center min-w-[80px] ${
            data.triage_level === 'EMERGENCY_ESCALATION' ? 'bg-red-600' : data.risk_score > 7 ? 'bg-orange-500' : 'bg-emerald-500'
          }`}>
            <span className="text-[8px] opacity-70">SCORE</span>
            <span className="text-2xl">{data.risk_score}</span>
            <span className="text-[8px] mt-1">{data.triage_level}</span>
          </div>
          <div className="space-y-2">
            <p className="font-medium text-slate-800">{data.rationale}</p>
            {data.red_flags_identified?.length > 0 && (
               <div className="flex flex-wrap gap-1">
                 {data.red_flags_identified.map((f: string, i: number) => (
                   <span key={i} className="px-2 py-0.5 bg-red-50 text-red-700 text-[10px] font-bold border border-red-100 rounded">FLAG: {f}</span>
                 ))}
               </div>
            )}
          </div>
        </div>
      );
    case AgentID.ORCHESTRATOR:
      return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <span className="text-[10px] font-bold text-slate-400 uppercase">Action Plan (Case: {data.case_id})</span>
            {data.tasks?.map((t: any, idx: number) => (
              <div key={idx} className="flex items-center gap-2 text-xs">
                <i className="fa-solid fa-check-circle text-indigo-500"></i>
                <span className="font-bold text-slate-700">{t.assignee}:</span>
                <span className="text-slate-600">{t.action || t.description}</span>
              </div>
            ))}
          </div>
          <div className="p-3 bg-amber-50 rounded-lg border border-amber-100">
             <span className="text-[10px] font-bold text-amber-800 uppercase block mb-1">Logistics & SLA</span>
             <div className="text-[11px] space-y-1">
               <p><span className="font-bold">SLA:</span> {data.sla_commitment}</p>
               <p><span className="font-bold">Referrals:</span> {data.referrals?.join(', ') || 'None'}</p>
               <p><span className="font-bold">Priority:</span> {data.scheduling_priority}</p>
             </div>
          </div>
        </div>
      );
    case AgentID.COACH:
      return (
        <div className="space-y-4">
          <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
             <h5 className="text-[10px] font-black text-emerald-800 uppercase mb-2">7-Day Micro Care Plan</h5>
             <div className="space-y-1">
                {data.seven_day_plan?.map((day: any, i: number) => (
                  <div key={i} className="text-xs flex gap-2">
                    <span className="font-bold text-emerald-700 min-w-[50px]">Day {i+1}:</span>
                    <span className="text-slate-700">{day.activity || day.task || day}</span>
                  </div>
