               <p><span className="font-bold">Referrals:</span> {data.referrals?.join(', ') || 'None'}</p>
               <p><span className="font-bold">Priority:</span> {data.scheduling_priority}</p>
             </div>
          </div>
        </div>
      );
    case AgentID.COACH:
      return (
        <div className="space-y-4">
          <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
             <h5 className="text-[10px] font-black text-emerald-800 uppercase mb-2">7-Day Micro Care Plan</h5>
             <div className="space-y-1">
                {data.seven_day_plan?.map((day: any, i: number) => (
                  <div key={i} className="text-xs flex gap-2">
                    <span className="font-bold text-emerald-700 min-w-[50px]">Day {i+1}:</span>
                    <span className="text-slate-700">{day.activity || day.task || day}</span>
                  </div>
                ))}
             </div>
          </div>
          <p className="text-xs italic text-slate-500 border-t pt-2">Guidance: {data.guidance_notes}</p>
        </div>
      );
    default:
      return <pre className="text-[10px] font-mono whitespace-pre-wrap">{JSON.stringify(data, null, 2)}</pre>;
  }
};

