                  {record.pain_level ?? 'N/A'}/10
                </span>
              </div>
              <div>
                <span className="text-[9px] text-slate-400 uppercase font-bold block">Mobility</span>
                <span className="font-semibold text-[10px]">{record.mobility_level || 'N/A'}</span>
