                 ))}
               </ul>
            </div>
          )}
        </div>
      );
    case AgentID.ORCHESTRATOR:
      return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="space-y-2">
            <span className="text-[10px] font-bold text-slate-400 uppercase">Action Plan (Case: {data.case_id})</span>
            {data.tasks?.map((t: any, idx: number) => (
              <div key={idx} className="flex items-center gap-2 text-xs">
                <i className="fa-solid fa-check-circle text-indigo-500"></i>
                <span className="font-bold text-slate-700">{t.assignee}:</span>
                <span className="text-slate-600">{t.action || t.description}</span>
              </div>
            ))}
          </div>
          <div className="p-3 bg-amber-50 rounded-lg border border-amber-100">
             <span className="text-[10px] font-bold text-amber-800 uppercase block mb-1">Logistics & SLA</span>
             <div className="text-[11px] space-y-1">
               <p><span className="font-bold">SLA:</span> {data.sla_commitment}</p>
               <p><span className="font-bold">Referrals:</span> {data.referrals?.join(', ') || 'None'}</p>
               <p><span className="font-bold">Priority:</span> {data.scheduling_priority}</p>
             </div>
          </div>
        </div>
      );
    case AgentID.COACH:
      return (
        <div className="space-y-4">
          <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
             <h5 className="text-[10px] font-black text-emerald-800 uppercase mb-2">7-Day Micro Care Plan</h5>
             <div className="space-y-1">
                {data.seven_day_plan?.map((day: any, i: number) => (
                  <div key={i} className="text-xs flex gap-2">
                    <span className="font-bold text-emerald-700 min-w-[50px]">Day {i+1}:</span>
