            </div>
          </div>
        </div>
      );
    case AgentID.COACH:
      return (
        <div className="space-y-4">
          <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
             <h5 className="text-[10px] font-black text-emerald-800 uppercase mb-2">7-Day Micro Care Plan</h5>
