import React, { useState } from 'react';
import { callAgent } from './services/gemini';
import { AgentID, WorkflowState, Patient, AgentResponse } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import WorkflowVisualizer from './components/WorkflowVisualizer';
import AgentTerminal from './components/AgentTerminal';
import Header from './components/Header';

const DEMO_PATIENTS: Patient[] = [
  { 
    id: '1', 
    name: 'Mrs. Evelyn Miller', 
    age: 82, 
    gender: 'Female',
    condition: 'Congestive Heart Failure', 
    status: 'monitoring',
    medicalHistory: {
      diagnosis: 'CHF, Osteoarthritis',
      medications: ['Lisinopril', 'Furosemide'],
      allergies: ['Penicillin']
    },
    contacts: [{ name: 'Sarah Miller', relation: 'Daughter', priority: 1 }]
  },
  { 
    id: '2', 
    name: 'Mr. Arthur Chen', 
    age: 79, 
    gender: 'Male',
    condition: 'Type 2 Diabetes', 
    status: 'stable',
    medicalHistory: {
      diagnosis: 'Diabetes, Hypertension',
      medications: ['Metformin', 'Amlodipine'],
      allergies: []
    },
    contacts: [{ name: 'Grace Chen', relation: 'Spouse', priority: 1 }]
  },
  { 
    id: '3', 
    name: 'Mrs. Dolores Vance', 
    age: 85, 
    gender: 'Female',
    condition: 'Post-Hip Surgery Recovery', 
    status: 'active',
    medicalHistory: {
      diagnosis: 'Post-Op Rehab, Osteoporosis',
      medications: ['Calcium', 'Warfarin'],
      allergies: ['Latex']
    },
    contacts: [{ name: 'Robert Vance', relation: 'Son', priority: 1 }]
  },
];

const App: React.FC = () => {
  const [selectedPatient, setSelectedPatient] = useState<Patient>(DEMO_PATIENTS[0]);
  const [workflow, setWorkflow] = useState<WorkflowState>({
    currentStep: 0,
    responses: {},
    isLoading: false,
  });

  const resetWorkflow = () => {
    setWorkflow({
      currentStep: 0,
      responses: {},
      isLoading: false,
    });
  };

  const handleRunWorkflow = async (scenarioText: string) => {
    setWorkflow(prev => ({ ...prev, isLoading: true, currentStep: 1, responses: {} }));

    try {
      // Step 1: Care Check-in Agent
      const checkInData = await callAgent(AgentID.CHECK_IN, { 
        patient: selectedPatient, 
        checkinRaw: scenarioText 
      });
      const checkInResponse: AgentResponse = {
        agentId: AgentID.CHECK_IN,
        title: 'Step 1: Care Check-in Interpretation',
        timestamp: new Date().toLocaleTimeString(),
        data: checkInData,
        rawJson: JSON.stringify(checkInData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 2, responses: { ...prev.responses, [AgentID.CHECK_IN]: checkInResponse } }));

      // Step 2: Data Capture & Normalization
      const normData = await callAgent(AgentID.NORMALIZATION, { 
        patient: selectedPatient, 
        previousContext: checkInData 
      });
      const normResponse: AgentResponse = {
        agentId: AgentID.NORMALIZATION,
        title: 'Step 2: Data Normalization',
        timestamp: new Date().toLocaleTimeString(),
        data: normData,
        rawJson: JSON.stringify(normData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 3, responses: { ...prev.responses, [AgentID.NORMALIZATION]: normResponse } }));

      // Step 3: Risk & Triage
      const riskData = await callAgent(AgentID.RISK_TRIAGE, { 
        patient: selectedPatient, 
        previousContext: normData 
      });
      const riskResponse: AgentResponse = {
        agentId: AgentID.RISK_TRIAGE,
        title: 'Step 3: Risk & Triage Assessment',
        timestamp: new Date().toLocaleTimeString(),
        data: riskData,
        rawJson: JSON.stringify(riskData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 4, responses: { ...prev.responses, [AgentID.RISK_TRIAGE]: riskResponse } }));

      // Step 4: Care Orchestrator
      const orchData = await callAgent(AgentID.ORCHESTRATOR, { 
        patient: selectedPatient, 
        previousContext: riskData 
      });
      const orchResponse: AgentResponse = {
        agentId: AgentID.ORCHESTRATOR,
        title: 'Step 4: Care Orchestration',
        timestamp: new Date().toLocaleTimeString(),
        data: orchData,
        rawJson: JSON.stringify(orchData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ ...prev, currentStep: 5, responses: { ...prev.responses, [AgentID.ORCHESTRATOR]: orchResponse } }));

      // Step 5: Care Coach
      const coachData = await callAgent(AgentID.COACH, { 
        patient: selectedPatient, 
        previousContext: { checkInData, normData, riskData, orchData } 
      });
      const coachResponse: AgentResponse = {
        agentId: AgentID.COACH,
        title: 'Step 5: Care Coaching & Guidelines',
        timestamp: new Date().toLocaleTimeString(),
        data: coachData,
        rawJson: JSON.stringify(coachData, null, 2),
        status: 'completed'
      };
      setWorkflow(prev => ({ 
        ...prev, 
        currentStep: 6, 
        isLoading: false, 
        responses: { ...prev.responses, [AgentID.COACH]: coachResponse } 
      }));

    } catch (err: any) {
      console.error(err);
      setWorkflow(prev => ({ ...prev, isLoading: false, error: 'Pipeline processing failed. Check logs for details.' }));
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        patients={DEMO_PATIENTS} 
        selectedId={selectedPatient.id} 
        onSelect={setSelectedPatient} 
      />

      <div className="flex-1 flex flex-col h-full">
        <Header />

        <main className="flex-1 overflow-y-auto p-6 space-y-6">
          <Dashboard 
            patient={selectedPatient} 
            onTriggerScenario={handleRunWorkflow} 
            isProcessing={workflow.isLoading}
            onReset={resetWorkflow}
          />

          <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
            <div className="xl:col-span-2">
              <WorkflowVisualizer 
                currentStep={workflow.currentStep} 
                responses={workflow.responses}
                isLoading={workflow.isLoading}
              />
            </div>
            <div className="xl:col-span-1">
              <AgentTerminal 
                responses={workflow.responses} 
                activeStep={workflow.currentStep} 
              />
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { AgentID, AgentResponse } from '../types';

interface WorkflowVisualizerProps {
  currentStep: number;
  responses: Record<string, AgentResponse>;
  isLoading: boolean;
}

const AGENT_META = [
  { id: AgentID.CHECK_IN, label: 'Check-in', icon: 'fa-phone-volume', color: 'indigo' },
  { id: AgentID.NORMALIZATION, label: 'Normalize', icon: 'fa-filter', color: 'blue' },
  { id: AgentID.RISK_TRIAGE, label: 'Risk & Triage', icon: 'fa-shield-heart', color: 'rose' },
  { id: AgentID.ORCHESTRATOR, label: 'Orchestrator', icon: 'fa-diagram-project', color: 'amber' },
  { id: AgentID.COACH, label: 'Care Coach', icon: 'fa-graduation-cap', color: 'emerald' },
];

const WorkflowVisualizer: React.FC<WorkflowVisualizerProps> = ({ currentStep, responses, isLoading }) => {
  const coachResponse = responses[AgentID.COACH];
  const summary = coachResponse?.data?.pipeline_summary;

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden h-full">
      <div className="px-6 py-4 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
          <i className="fa-solid fa-network-wired text-indigo-600"></i>
          ARP Care Pipeline Execution
        </h3>
        {isLoading && (
          <div className="flex items-center gap-2 text-indigo-600 text-xs font-bold uppercase tracking-widest">
            <i className="fa-solid fa-circle-notch animate-spin"></i>
            Pipeline Processing...
          </div>
        )}
      </div>

      <div className="p-8">
        {summary && (
          <div className="mb-8 p-6 bg-indigo-50 border border-indigo-100 rounded-2xl animate-in fade-in zoom-in duration-500">
             <div className="flex items-center gap-3 mb-3">
                <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
                  <i className="fa-solid fa-list-check text-sm"></i>
                </div>
                <h4 className="text-indigo-900 font-bold uppercase tracking-wider text-xs">PIPELINE_SUMMARY</h4>
             </div>
             <p className="text-slate-700 text-sm leading-relaxed font-medium">
               {summary}
             </p>
          </div>
        )}

        <div className="relative">
          {/* Timeline Line */}
          <div className="absolute top-[40px] left-[5%] right-[5%] h-1 bg-slate-100 z-0"></div>
          <div 
            className="absolute top-[40px] left-[5%] h-1 bg-indigo-600 z-0 transition-all duration-700 ease-out"
            style={{ width: `${Math.max(0, (currentStep - 1) * 22.5)}%` }}
          ></div>

          <div className="flex justify-between items-start relative z-10">
            {AGENT_META.map((agent, idx) => {
              const status = responses[agent.id] ? 'completed' : currentStep === idx + 1 ? 'active' : 'pending';

              return (
                <div key={agent.id} className="flex flex-col items-center text-center max-w-[120px]">
                  <div className={`w-20 h-20 rounded-2xl flex items-center justify-center transition-all duration-500 shadow-lg ${
                    status === 'completed' ? `bg-${agent.color}-600 text-white scale-100` : 
                    status === 'active' ? `bg-white border-4 border-indigo-600 text-indigo-600 scale-110 animate-pulse` : 
                    'bg-slate-100 text-slate-400'
                  }`}>
                    <i className={`fa-solid ${agent.icon} text-2xl`}></i>
                  </div>
                  <div className="mt-4">
                    <p className={`text-sm font-bold ${status === 'pending' ? 'text-slate-400' : 'text-slate-900'}`}>
                      {agent.label}
                    </p>
                    <p className="text-[10px] font-semibold text-slate-400 uppercase mt-1">
                      {status === 'completed' ? 'Artifact Ready' : status === 'active' ? 'Executing Step' : 'Queued'}
                    </p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="mt-12 space-y-4">
          {(Object.values(responses) as AgentResponse[]).map((resp: AgentResponse) => (
            <div key={resp.agentId} className="bg-slate-50 border border-slate-200 rounded-xl p-5 hover:border-indigo-300 transition-colors animate-in fade-in slide-in-from-bottom-2">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-3">
                  <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${
                    resp.agentId === AgentID.RISK_TRIAGE ? 'bg-rose-100 text-rose-700' : 'bg-indigo-100 text-indigo-700'
                  }`}>
                    {resp.agentId.replace('_', ' ')}
                  </span>
                  <h4 className="font-bold text-slate-900">{resp.title}</h4>
                </div>
                <span className="text-xs text-slate-400 font-mono">{resp.timestamp}</span>
              </div>

              <div className="text-sm text-slate-600 leading-relaxed">
                {renderAgentContent(resp)}
              </div>
            </div>
          ))}

          {currentStep === 0 && !isLoading && (
            <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl text-slate-400">
              <i className="fa-solid fa-robot text-4xl mb-4 opacity-20"></i>
              <p className="font-medium">Configure and run a care pipeline to generate artifacts</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const renderAgentContent = (resp: AgentResponse) => {
  const data = resp.data;
  switch (resp.agentId) {
    case AgentID.CHECK_IN:
      return (
        <div className="space-y-3">
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white p-3 rounded border border-slate-200">
              <span className="font-bold text-slate-900 block text-[10px] uppercase mb-1">Status & Priority</span>
              <div className="text-xs space-y-1">
                <p><span className="text-slate-400 font-bold uppercase">Contact:</span> {data.contact_status}</p>
                <p><span className="text-slate-400 font-bold uppercase">Priority:</span> {data.initial_priority}</p>
              </div>
            </div>
            <div className="bg-indigo-50 p-3 rounded border border-indigo-100">
              <span className="font-bold text-indigo-900 block text-[10px] uppercase mb-1">Next Action</span>
              <p className="text-xs font-bold text-indigo-700">{data.next_action}</p>
