  const handleAction = (type: string) => {
    let scenario = "";
    if (type === 'CALLBACK') scenario = `Family member requested a nurse callback for ${patient.name}. Reason: "Routine follow-up or specific question about the care plan."`;
    if (type === 'VITAL_UPLOAD') scenario = `Family uploaded new measurement for ${patient.name}: ${measurement.type} = ${measurement.value}. "Please verify if this is optimal."`;
    if (type === 'OBSERVATION') { setShowInputModal('OBSERVATION'); return; }
    if (type === 'SUBMIT_OBSERVATION') scenario = `Family added observation for ${patient.name}: [${observation.type}] "${observation.text}". "Noting this for the next nurse review."`;
    if (type === 'ACKNOWLEDGE') scenario = `Family acknowledged the current health alert for ${patient.name}. "We are aware and monitoring."`;

    if (scenario) onTriggerAction(scenario);
    setShowInputModal(null);
