import { NextResponse } from 'next/server';
import { generateWorkflowResponse } from '../../lib/ai';
import { workflow } from '../../lib/workflow';
import { EventType } from '../../types';

export async function POST(req: Request) {
  try {
    const { rawInput, patient, eventType } = await req.json();

    if (!rawInput || !patient) {
      return NextResponse.json({ error: 'Missing required parameters' }, { status: 400 });
    }

    // Determine the agent ID based on the event type
    let agentId;
    if (eventType === EventType.FAMILY_EVENT) {
      agentId = "FAMILY_APP_AGENT";
    } else {
      agentId = "INITIAL_AGENT";
    }

    const aiResponse = await generateWorkflowResponse({ rawInput, patient, eventType, agentId });

    // Assuming aiResponse.content contains your output, e.g., JSON
    const workflowResponse = workflow(aiResponse.content, patient);
    return NextResponse.json({ ...workflowResponse });
  } catch (error) {
    console.error('API Error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
]]></content>
