import { GoogleGenerativeAI } from '@google/generative-ai';
import { SYSTEM_PROMPTS } from './prompts';
import { EventType } from '../types';

interface GenerateWorkflowResponseProps {
  rawInput: string;
  patient: any;
  eventType: EventType;
  agentId: string;
}

const MODEL = process.env.GOOGLE_MODEL_NAME || 'gemini-1.0-pro';

const ai = new GoogleGenerativeAI(process.env.GOOGLE_API_KEY!);
const model = ai.getGenerativeModel({ model: MODEL });

export async function generateWorkflowResponse({ rawInput, patient, eventType, agentId }: GenerateWorkflowResponseProps) {
  let prompt: string;

  if (eventType === EventType.FAMILY_EVENT) {
    prompt = `
      RAW starts with "FAMILY_EVENT:", interpret it as a caregiver update from the Family App.
      Format your output strictly as a JSON object matching the required structure.
      \`\`\`json
        {
          "agent_responses": [],
          "family_app_ui": {}
        }
      \`\`\`
    `;

    if (rawInput && rawInput.startsWith("FAMILY_EVENT:")) {
        prompt = `
        RAW: ${rawInput}
        `;
    }

  } else {
    prompt = `
     RAW: ${rawInput}
    `;
  }

  const response = await model.generateContent({
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_PROMPTS[agentId],
      responseMimeType: "application/json",
    },
  });

  return JSON.parse(response.text);
}
]]></content>
