const App: React.FC = () => {
  const [view, setView] = useState<'ADMIN' | 'FAMILY'>('ADMIN');
  const [locale, setLocale] = useState<Locale>('en');
  const [selectedPatient, setSelectedPatient] = useState<Patient>(DEMO_PATIENTS[0]);
  const [workflow, setWorkflow] = useState<WorkflowState>({
    currentStep: 0,
    responses: {},
    isLoading: false,
  });

  const t = translations[locale];

  const resetWorkflow = () => {
    setWorkflow({
      currentStep: 0,
      responses: {},
      isLoading: false,
    });
  };

  const handleRunWorkflow = async (scenarioText: string, familyEvent?: FamilyEvent) => {
    setWorkflow(prev => ({ ...prev, isLoading: true, currentStep: 1, responses: {} }));
    const currentState = {
      triage: workflow.responses[AgentID.RISK_TRIAGE]?.data,
      case: workflow.responses[AgentID.ORCHESTRATOR]?.data,
      coach: workflow.responses[AgentID.COACH]?.data
    };

    try {
      const agents = [
        AgentID.CHECK_IN,
        AgentID.NORMALIZATION,
        AgentID.RISK_TRIAGE,
        AgentID.ORCHESTRATOR,
        AgentID.COACH
      ];

      let prevContext = null;
      const responses: Record<string, AgentResponse> = {};

      for (let i = 0; i < agents.length; i++) {
        const agentId = agents[i];
        const stepNum = i + 1;
        setWorkflow(prev => ({ ...prev, currentStep: stepNum }));

        const context = agentId === AgentID.CHECK_IN 
          ? { patient: selectedPatient, checkinRaw: scenarioText, familyEvent, currentState }
          : agentId === AgentID.COACH 
            ? { patient: selectedPatient, previousContext: responses, currentState }
            : { patient: selectedPatient, previousContext: prevContext, currentState };

        const data = await callAgent(agentId, context, locale);
        prevContext = data;

        const response: AgentResponse = {
          agentId,
          title: `Step ${stepNum}: ${agentId.replace('_', ' ')}`,
          timestamp: new Date().toLocaleTimeString(),
          data,
          rawJson: JSON.stringify(data, null, 2),
          status: 'completed'
        };

        responses[agentId] = response;
        setWorkflow(prev => ({ ...prev, responses: { ...prev.responses, [agentId]: response } }));
      }

      setWorkflow(prev => ({ ...prev, currentStep: 6, isLoading: false }));

    } catch (err: any) {
      console.error(err);
      setWorkflow(prev => ({ ...prev, isLoading: false, error: 'Pipeline processing failed.' }));
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      {view === 'ADMIN' && (
        <Sidebar 
          patients={DEMO_PATIENTS} 
          selectedId={selectedPatient.id} 
          onSelect={setSelectedPatient}
          locale={locale}
        />
      )}

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <Header view={view} setView={setView} locale={locale} setLocale={setLocale} />

        <main className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
          {view === 'ADMIN' ? (
            <>
              <Dashboard 
                patient={selectedPatient} 
                onTriggerScenario={handleRunWorkflow} 
                isProcessing={workflow.isLoading}
                onReset={resetWorkflow}
                locale={locale}
              />

              <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                <div className="xl:col-span-2">
                  <WorkflowVisualizer 
                    currentStep={workflow.currentStep} 
                    responses={workflow.responses}
                    isLoading={workflow.isLoading}
                    locale={locale}
                  />
                </div>
                <div className="xl:col-span-1">
                  <AgentTerminal 
                    responses={workflow.responses} 
                    activeStep={workflow.currentStep} 
                    locale={locale}
                  />
                </div>
              </div>
            </>
          ) : (
            <FamilyApp 
              patient={selectedPatient} 
              workflow={workflow}
              onTriggerAction={handleRunWorkflow}
              isLoading={workflow.isLoading}
              locale={locale}
            />
          )}
        </main>
      </div>
    </div>
  );
};

