            "{patient.baselineNotes}"
          </p>
        </div>
      </div>

      <div className="bg-indigo-900 rounded-2xl p-6 text-white shadow-xl relative overflow-hidden">
        <div className="flex items-center gap-3 mb-4 relative z-10">
          <div className="w-10 h-10 bg-indigo-500/30 rounded-full flex items-center justify-center">
            <i className="fa-solid fa-microphone-lines text-indigo-200"></i>
          </div>
          <div>
            <h3 className="font-bold text-lg">{t.simulateInteraction}</h3>
            <p className="text-indigo-300 text-sm">{locale === 'zh' ? '输入语音记录或选择演示场景以触发多代理流水线。' : 'Input raw voice transcript or select a demo scenario to trigger the multi-agent pipeline.'}</p>
          </div>
        </div>

        <div className="space-y-4 relative z-10">
          <textarea
            value={scenarioInput}
            onChange={(e) => setScenarioInput(e.target.value)}
            placeholder={`${locale === 'zh' ? '输入报告内容：' : 'Paste transcript for '} ${patient.name}...`}
            className="w-full h-24 bg-indigo-950/50 border border-indigo-700/50 rounded-xl p-4 text-indigo-100 placeholder:text-indigo-400 focus:outline-none focus:border-indigo-400 transition-all resize-none font-mono text-sm"
          ></textarea>

          <div className="flex flex-wrap gap-2">
            {presets.map((p, idx) => (
              <button
                key={idx}
                onClick={() => setScenarioInput(p.text)}
                className="px-3 py-1.5 bg-indigo-800 hover:bg-indigo-700 text-[10px] font-black uppercase tracking-widest rounded-full transition-all border border-indigo-700 hover:scale-105"
              >
                {p.label}
              </button>
            ))}
          </div>

          <button
            disabled={isProcessing || !scenarioInput.trim()}
            onClick={() => onTriggerScenario(scenarioInput)}
            className={`w-full py-4 rounded-xl font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-2 transition-all ${
              isProcessing 
              ? 'bg-slate-700 cursor-not-allowed text-slate-400' 
              : 'bg-white text-indigo-900 hover:bg-indigo-50 active:scale-[0.98] shadow-lg shadow-indigo-400/20'
            }`}
          >
            {isProcessing ? (
              <>
                <i className="fa-solid fa-spinner animate-spin"></i>
                {t.orchestrating}
              </>
            ) : (
              <>
                <i className="fa-solid fa-play"></i>
                {t.processEvent}
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Patient, WorkflowState, AgentID, FamilyEvent } from '../types';
import { Locale, translations } from '../i18n';

interface FamilyAppProps {
  patient: Patient;
  workflow: WorkflowState;
  onTriggerAction: (scenario: string, event?: FamilyEvent) => void;
  isLoading: boolean;
  locale: Locale;
}

const FamilyApp: React.FC<FamilyAppProps> = ({ patient, workflow, onTriggerAction, isLoading, locale }) => {
  const [activeTab, setActiveTab] = useState<'HOME' | 'ALERTS' | 'VITALS' | 'PLAN'>('HOME');
  const [showInputModal, setShowInputModal] = useState<'VITAL' | 'OBSERVATION' | null>(null);
  const [measurement, setMeasurement] = useState({ type: 'BP', value: '' });
  const [observation, setObservation] = useState({ type: 'behavioral', text: '' });

  const t = translations[locale];
  const coachResponse = workflow.responses[AgentID.COACH]?.data;
  const familyUI = coachResponse?.family_app_ui;
  const triageResponse = workflow.responses[AgentID.RISK_TRIAGE]?.data;

  // Rich Fallbacks
  const homeData = familyUI?.home_dashboard || {
    today_status_card: { title: t.monitoringActive, subtitle: "All systems operational", status_color: "emerald" },
    risk_level_card: { score: triageResponse?.risk_score || 12, label: triageResponse?.triage_level || t.standardMonitoring, recommendation: "Daily routine check-ins are proceeding normally." },
    quick_actions: [
      { label: t.requestNurse, action_id: "CALLBACK" },
      { label: t.logObservation, action_id: "OBSERVATION" }
    ],
    trend_summary_7d: { metric: "Care Stability", change: "+5%", insight: "" }
  };

  const alerts = familyUI?.alerts_inbox || [];

  const handleAction = (type: string) => {
    let scenario = "";
    let event: FamilyEvent | undefined;

    const baseEvent = {
      timestamp: new Date().toISOString(),
      caregiver_id: "CG-001",
      patient_id: patient.id
    };

    if (type === 'CALLBACK') {
      scenario = `Family requested nurse callback.`;
      event = { 
        ...baseEvent, 
        event_type: 'REQUEST_NURSE_CALLBACK', 
        reason: "Requesting support.",
        preferred_time_window: "within 1 hour"
      };
    }
    if (type === 'VITAL_UPLOAD') {
      scenario = `Family uploaded ${measurement.type} measurement: ${measurement.value}`;
      event = { ...baseEvent, event_type: 'UPLOAD_MEASUREMENT', context_note: "Manual Entry" };
    }
    if (type === 'OBSERVATION') { setShowInputModal('OBSERVATION'); return; }
    if (type === 'SUBMIT_OBSERVATION') {
      scenario = `Family added observation: ${observation.text}`;
      event = { ...baseEvent, event_type: 'ADD_OBSERVATION' };
    }

    if (scenario) onTriggerAction(scenario, event);
    setShowInputModal(null);
  };

  return (
    <div className="max-w-2xl mx-auto pb-32 px-4">
      <div className="bg-white rounded-[2rem] p-6 shadow-sm border border-slate-100 mb-6 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-emerald-50 rounded-2xl flex items-center justify-center border border-emerald-100 shadow-inner">
             <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${patient.name}`} className="w-12 h-12" alt="patient" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-slate-800">{patient.name}</h2>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{patient.age}Y • {patient.gender}</p>
          </div>
        </div>
        <div className={`w-3 h-3 rounded-full animate-pulse bg-${homeData.today_status_card.status_color}-500`}></div>
      </div>

      {activeTab === 'HOME' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className={`bg-gradient-to-br rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden ${
            homeData.today_status_card.status_color === 'rose' ? 'from-slate-900 to-rose-950 shadow-rose-200' :
            homeData.today_status_card.status_color === 'amber' ? 'from-slate-900 to-amber-950 shadow-amber-200' :
            'from-slate-900 to-indigo-950 shadow-indigo-200'
          }`}>
             <div className="relative z-10">
               <div className="flex justify-between items-start mb-6">
                 <span className="text-[10px] font-black uppercase tracking-[0.2em] opacity-60">{t.status}: {homeData.today_status_card.title}</span>
                 <div className="px-3 py-1 bg-white/10 rounded-full border border-white/20 text-[10px] font-black uppercase tracking-widest">
                   {homeData.risk_level_card.label}
                 </div>
               </div>
               <div className="flex items-baseline gap-2">
                 <h3 className="text-6xl font-black tracking-tighter">{homeData.risk_level_card.score}%</h3>
                 <span className="text-lg font-bold opacity-60">{t.safetyIndex}</span>
               </div>
               <div className="mt-8 bg-black/20 backdrop-blur-md rounded-3xl p-6 border border-white/10">
                 <p className="text-sm font-medium leading-relaxed opacity-90 italic">"{homeData.risk_level_card.recommendation}"</p>
                 <div className="flex gap-3 mt-6">
                    {homeData.quick_actions.map((qa: any, i: number) => (
                      <button key={i} onClick={() => handleAction(qa.action_id)} className="flex-1 py-4 bg-white text-slate-900 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">
                        {qa.label}
                      </button>
                    ))}
                 </div>
               </div>
             </div>
          </div>
        </div>
      )}

      {activeTab === 'ALERTS' && (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
           <h3 className="text-xl font-black text-slate-800 uppercase tracking-widest mb-6 px-2">{t.alertsInbox}</h3>
           {alerts.map((alert: any) => (
             <div key={alert.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex gap-4">
               <div className="flex-1">
                 <h4 className="text-sm font-bold text-slate-800">{alert.title}</h4>
                 <p className="text-xs text-slate-500 mt-2">{alert.message}</p>
               </div>
             </div>
           ))}
        </div>
      )}

      {activeTab === 'VITALS' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm">
            <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8">{t.healthTrends}</h4>
            <button onClick={() => setShowInputModal('VITAL')} className="w-full py-5 bg-slate-900 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-2xl">
              + {t.recordReading}
            </button>
          </div>
        </div>
      )}

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-[calc(100%-3rem)] max-w-sm bg-slate-900/95 backdrop-blur-xl rounded-[2.5rem] p-2 shadow-2xl flex items-center justify-around z-50 border border-white/10">
         {[
           { id: 'HOME', icon: 'fa-house-chimney', label: t.home },
           { id: 'ALERTS', icon: 'fa-bell', label: t.inbox },
           { id: 'VITALS', icon: 'fa-heart-pulse', label: t.health },
           { id: 'PLAN', icon: 'fa-clipboard-list', label: t.coach }
         ].map(tab => (
           <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-4 rounded-[2rem] transition-all flex flex-col items-center gap-1.5 ${activeTab === tab.id ? 'bg-white text-slate-900' : 'text-slate-400'}`}>
             <i className={`fa-solid ${tab.icon} text-lg`}></i>
             <span className="text-[8px] font-black uppercase tracking-widest">{tab.label}</span>
           </button>
         ))}
      </div>

      {showInputModal === 'VITAL' && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl">
            <h3 className="text-lg font-black text-slate-800 uppercase tracking-widest mb-6">{t.recordReading}</h3>
            <div className="space-y-4">
               <select className="w-full bg-slate-50 border p-4 rounded-2xl font-bold text-sm">
                 <option value="BP">BP</option>
                 <option value="SPO2">SpO2</option>
               </select>
               <input type="text" placeholder="Value" className="w-full bg-slate-50 border p-4 rounded-2xl font-bold text-sm" />
               <button onClick={() => handleAction('VITAL_UPLOAD')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">{t.sync}</button>
               <button onClick={() => setShowInputModal(null)} className="w-full py-2 text-slate-400 font-bold text-xs uppercase">{t.cancel}</button>
            </div>
          </div>
        </div>
      )}

      {isLoading && (
        <div className="fixed inset-0 z-[100] bg-white/80 backdrop-blur-md flex flex-col items-center justify-center">
           <div className="w-16 h-16 bg-slate-900 rounded-[2rem] flex items-center justify-center text-white shadow-2xl animate-bounce">
              <i className="fa-solid fa-satellite-dish text-2xl"></i>
           </div>
        </div>
      )}
    </div>
  );
};

export default FamilyApp;

import React from 'react';
import { AgentID, AgentResponse } from '../types';
import { Locale, translations } from '../i18n';

interface WorkflowVisualizerProps {
  currentStep: number;
  responses: Record<string, AgentResponse>;
  isLoading: boolean;
  locale: Locale;
}

const AGENT_META = [
  { id: AgentID.CHECK_IN, label: 'Check-in', icon: 'fa-phone-volume', color: 'indigo' },
  { id: AgentID.NORMALIZATION, label: 'Normalize', icon: 'fa-filter', color: 'blue' },
  { id: AgentID.RISK_TRIAGE, label: 'Risk & Triage', icon: 'fa-shield-heart', color: 'rose' },
  { id: AgentID.ORCHESTRATOR, label: 'Orchestrator', icon: 'fa-diagram-project', color: 'amber' },
  { id: AgentID.COACH, label: 'Care Coach', icon: 'fa-graduation-cap', color: 'emerald' },
];

const WorkflowVisualizer: React.FC<WorkflowVisualizerProps> = ({ currentStep, responses, isLoading, locale }) => {
  const t = translations[locale];
  const coachResponse = responses[AgentID.COACH];
  const summary = coachResponse?.data?.pipeline_summary;

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden h-full">
      <div className="px-6 py-4 border-b border-slate-100 bg-slate-50 flex items-center justify-between">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
          <i className="fa-solid fa-network-wired text-indigo-600"></i>
          {t.pipelineExecution}
        </h3>
        {isLoading && (
          <div className="flex items-center gap-2 text-indigo-600 text-xs font-bold uppercase tracking-widest">
            <i className="fa-solid fa-circle-notch animate-spin"></i>
            {t.orchestrating}
          </div>
        )}
      </div>

      <div className="p-8">
        {summary && (
          <div className="mb-8 p-6 bg-indigo-50 border border-indigo-100 rounded-2xl">
             <div className="flex items-center gap-3 mb-3">
                <h4 className="text-indigo-900 font-bold uppercase tracking-wider text-xs">{t.pipelineSummary}</h4>
             </div>
             <p className="text-slate-700 text-sm leading-relaxed font-medium">{summary}</p>
          </div>
        )}

        <div className="relative">
          <div className="absolute top-[40px] left-[5%] right-[5%] h-1 bg-slate-100 z-0"></div>
          <div className="absolute top-[40px] left-[5%] h-1 bg-indigo-600 z-0 transition-all duration-700 ease-out" style={{ width: `${Math.max(0, (currentStep - 1) * 22.5)}%` }}></div>

          <div className="flex justify-between items-start relative z-10">
            {AGENT_META.map((agent, idx) => {
              const status = responses[agent.id] ? 'completed' : currentStep === idx + 1 ? 'active' : 'pending';
              return (
                <div key={agent.id} className="flex flex-col items-center text-center max-w-[120px]">
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center transition-all shadow-md ${
                    status === 'completed' ? `bg-${agent.color}-600 text-white` : 
                    status === 'active' ? `bg-white border-2 border-indigo-600 text-indigo-600 animate-pulse` : 
                    'bg-slate-100 text-slate-400'
                  }`}>
                    <i className={`fa-solid ${agent.icon} text-xl`}></i>
                  </div>
                  <div className="mt-2 text-[10px] font-bold text-slate-900">{agent.label}</div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="mt-12 space-y-4">
          {(Object.values(responses) as AgentResponse[]).map((resp: AgentResponse) => (
            <div key={resp.agentId} className="bg-slate-50 border border-slate-200 rounded-xl p-4">
              <h4 className="font-bold text-slate-900 text-xs mb-2 uppercase">{resp.title}</h4>
              <div className="text-xs text-slate-600">
                {typeof resp.data === 'object' ? <pre className="whitespace-pre-wrap">{JSON.stringify(resp.data, null, 2)}</pre> : resp.data}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default WorkflowVisualizer;

import React, { useState } from 'react';
