    <div className="bg-slate-900 rounded-2xl shadow-xl flex flex-col h-full border border-slate-800 overflow-hidden min-h-[500px]">
      <div className="px-5 py-3 border-b border-slate-800 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-xs font-bold text-slate-400 font-mono uppercase tracking-wider">{t.sysExplorer}</span>
        </div>
        <div className="flex bg-slate-800 rounded-lg p-1">
          <button onClick={() => setView('LOGS')} className={`px-3 py-1 text-[10px] font-bold rounded-md transition-colors ${view === 'LOGS' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}>
            {t.logs}
          </button>
          <button onClick={() => setView('CONFIG')} className={`px-3 py-1 text-[10px] font-bold rounded-md transition-colors ${view === 'CONFIG' ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}>
            {t.config}
